package br.com.saqz.groups.adapter.output.jdbc.finance

import br.com.saqz.groups.application.finance.expense.*
import br.com.saqz.groups.domain.GroupRole
import br.com.saqz.groups.domain.finance.expense.*
import org.springframework.jdbc.core.simple.JdbcClient
import java.sql.*
import java.util.UUID
import javax.sql.DataSource

class JdbcExpenseRepository(dataSource:DataSource):ExpenseRepository{
    private val jdbc=JdbcClient.create(dataSource)
    override fun role(actor:UUID,group:UUID):GroupRole?=jdbc.sql(ROLE).param("actor",actor).param("group",group).query(String::class.java).optional().map(GroupRole::valueOf).orElse(null)
    override fun list(group:UUID)=jdbc.sql("$SELECT WHERE group_id=:group ORDER BY expense_date DESC,id").param("group",group).query(::map).list().map{ExpenseWithEvents(it,events(it.id))}
    override fun find(group:UUID,id:UUID)=jdbc.sql("$SELECT WHERE group_id=:group AND id=:id").param("group",group).param("id",id).query(::map).optional().orElse(null)?.let{ExpenseWithEvents(it,events(it.id))}
    override fun create(expense:Expense,event:ExpenseEvent):Boolean{val inserted=bind(jdbc.sql("INSERT INTO group_expenses (id,group_id,description,amount_cents,expense_date,category,custom_category,notes,status,created_by_user_id,changed_by_user_id,version,created_at,updated_at) VALUES (:id,:group,:description,:amount,:date,:category,:custom,:notes,:status,:actor,:actor,1,:now,:now) ON CONFLICT (id) DO NOTHING"),expense,event.actorId,event.occurredAt).update();if(inserted==1)insertEvent(expense,event);return inserted==1}
    override fun update(expense:Expense,event:ExpenseEvent,expectedVersion:Long):Boolean{val updated=bind(jdbc.sql("UPDATE group_expenses SET description=:description,amount_cents=:amount,expense_date=:date,category=:category,custom_category=:custom,notes=:notes,status=:status,changed_by_user_id=:actor,version=:version,updated_at=:now WHERE id=:id AND group_id=:group AND version=:expected"),expense,event.actorId,event.occurredAt).param("expected",expectedVersion).update();if(updated==1)insertEvent(expense,event);return updated==1}
    private fun bind(s:JdbcClient.StatementSpec,e:Expense,actor:UUID,time:java.time.Instant)=s.param("id",e.id).param("group",e.groupId).param("description",e.snapshot.description).param("amount",e.snapshot.amountCents).param("date",e.snapshot.expenseDate).param("category",e.snapshot.category.name).param("custom",e.snapshot.customCategory,Types.VARCHAR).param("notes",e.snapshot.notes,Types.VARCHAR).param("status",e.status.name).param("actor",actor).param("version",e.version).param("now",Timestamp.from(time))
    private fun insertEvent(expense:Expense,e:ExpenseEvent){val s=e.snapshot;jdbc.sql("INSERT INTO group_expense_events (id,expense_id,group_id,actor_user_id,action,description,amount_cents,expense_date,category,custom_category,notes,status,version,occurred_at) VALUES (:id,:expense,:group,:actor,:action,:description,:amount,:date,:category,:custom,:notes,:status,:version,:now)").param("id",e.id).param("expense",expense.id).param("group",expense.groupId).param("actor",e.actorId).param("action",e.action.name).param("description",s.description).param("amount",s.amountCents).param("date",s.expenseDate).param("category",s.category.name).param("custom",s.customCategory,Types.VARCHAR).param("notes",s.notes,Types.VARCHAR).param("status",e.status.name).param("version",e.version).param("now",Timestamp.from(e.occurredAt)).update()}
    private fun events(id:UUID)=jdbc.sql("SELECT id,expense_id,actor_user_id,action,description,amount_cents,expense_date,category,custom_category,notes,status,version,occurred_at FROM group_expense_events WHERE expense_id=:id ORDER BY occurred_at,id").param("id",id).query{r,_->ExpenseEvent(r.getObject("id",UUID::class.java),r.getObject("expense_id",UUID::class.java),r.getObject("actor_user_id",UUID::class.java),ExpenseAction.valueOf(r.getString("action")),snapshot(r),ExpenseStatus.valueOf(r.getString("status")),r.getLong("version"),r.getTimestamp("occurred_at").toInstant())}.list()
    private fun map(r:ResultSet,@Suppress("UNUSED_PARAMETER") row:Int)=Expense(r.getObject("id",UUID::class.java),r.getObject("group_id",UUID::class.java),snapshot(r),ExpenseStatus.valueOf(r.getString("status")),r.getLong("version"))
    private fun snapshot(r:ResultSet)=ExpenseSnapshot(r.getString("description"),r.getLong("amount_cents"),r.getObject("expense_date",java.time.LocalDate::class.java),ExpenseCategory.valueOf(r.getString("category")),r.getString("custom_category"),r.getString("notes"))
    private companion object{const val SELECT="SELECT id,group_id,description,amount_cents,expense_date,category,custom_category,notes,status,version FROM group_expenses";const val ROLE="""SELECT CASE WHEN g.owner_user_id=:actor THEN 'OWNER' ELSE m.role END FROM access_groups g LEFT JOIN group_memberships m ON m.group_id=g.id AND m.user_id=:actor WHERE g.id=:group AND (g.owner_user_id=:actor OR m.user_id IS NOT NULL)"""}
}
